@page "/privacy"
@attribute [ExcludeFromInteractiveRouting]
@using Microsoft.AspNetCore.Http
@inject IHttpContextAccessor HttpContextAccessor

<PageTitle>Privacy Policy</PageTitle>

<h1>Privacy Policy</h1>

@if (_hasConsent)
{
    <div class="alert alert-success" role="alert">
        ✅ You have already accepted our cookie policy.
    </div>
}
else
{
    <div class="alert alert-warning" role="alert">
        ⚠️ You have not yet accepted our cookie policy.
    </div>
}

<h2>How we use cookies</h2>
<p>
    This site uses cookies to improve your experience. By continuing to browse
    the site you are agreeing to our use of cookies.
</p>

<h2>What data we collect</h2>
<p>
    We may collect information about your browsing session, including pages
    visited and time spent on each page, to help us improve the site.
</p>

@code {
    private bool _hasConsent;

    protected override void OnInitialized()
    {
        var context = HttpContextAccessor.HttpContext;
        if (context is not null)
        {
            _hasConsent = context.Request.Cookies.ContainsKey("consent");
        }
    }
}

